from detoxify import Detoxify
from prometheus_client import Counter, Histogram
import time

classifier = Detoxify("original")   # load once at startup

BLOCK_COUNTER = Counter("llm_toxicity_blocks_total", "Blocked responses", ["category"])
SCORE_HIST = Histogram(
    "llm_toxicity_score",
    "Toxicity scores (sampled)",
    ["model"],
    buckets=[0.1, 0.2, 0.3, 0.5, 0.7, 0.8, 0.9, 0.95, 0.99],
)

THRESHOLDS = {
    "toxicity": 0.80,
    "severe_toxicity": 0.50,
    "identity_attack": 0.60,
    "threat": 0.50,
}

def check_toxicity(text: str, model: str = "unknown") -> dict:
    t0 = time.perf_counter()
    scores = classifier.predict(text)
    latency_ms = (time.perf_counter() - t0) * 1000

    SCORE_HIST.labels(model=model).observe(scores["toxicity"])

    for cat, threshold in THRESHOLDS.items():
        if scores.get(cat, 0) > threshold:
            BLOCK_COUNTER.labels(category=cat).inc()
            return {"block": True, "category": cat, "score": scores[cat],
                    "latency_ms": latency_ms}
    return {"block": False, "latency_ms": latency_ms}

from fastapi import Request, Response
from fastapi.responses import JSONResponse
import json

@app.middleware("http")
async def toxicity_guard(request: Request, call_next):
    response = await call_next(request)

    if (request.url.path == "/v1/chat/completions"
            and response.headers.get("content-type","").startswith("application/json")):
        body = b""
        async for chunk in response.body_iterator:
            body += chunk
        data = json.loads(body)

        content = data.get("choices",[{}])[0].get("message",{}).get("content","")
        model = data.get("model", "unknown")
        if content:
            result = check_toxicity(content, model)
            if result["block"]:
                return JSONResponse(status_code=200, content={
                    "choices": [{"message": {
                        "content": "I cannot provide that response."
                    }, "finish_reason": "content_filter"}]
                })
        return Response(content=body, status_code=response.status_code,
                        headers=dict(response.headers))
    return response

import asyncio, httpx

audit_queue: asyncio.Queue = asyncio.Queue(maxsize=10000)

async def enqueue_for_audit(request_id: str, model: str, response: str):
    try:
        audit_queue.put_nowait({"request_id": request_id, "model": model,
                                 "response": response})
    except asyncio.QueueFull:
        pass   # drop; never block request path

async def audit_worker():
    async with httpx.AsyncClient() as client:
        while True:
            item = await audit_queue.get()
            try:
                scores = await perspective_score(item["response"], client)
                await store_audit(item["request_id"], scores)
                if scores.get("TOXICITY", 0) > 0.70:
                    await send_alert(item)
            except Exception as e:
                pass   # log and continue
            finally:
                audit_queue.task_done()

@app.on_event("startup")
async def start_audit_workers():
    for _ in range(5):
        asyncio.create_task(audit_worker())

from sklearn.metrics import precision_recall_curve

def calibrate_threshold(
    scores: list,
    labels: list,          # 1=toxic, 0=clean
    target_recall: float = 0.95,
) -> float:
    precisions, recalls, thresholds = precision_recall_curve(labels, scores)
    for precision, recall, threshold in zip(precisions, recalls, thresholds):
        if recall <= target_recall:
            print(f"Threshold {threshold:.2f}: recall={recall:.2f}, precision={precision:.2f}")
            return float(threshold)
    return 0.5

